def ui_text(value):
    text = str(value or "")
    replacements = {
        "Automation:": "Автоматизация:",
        "AI daily digest": "Ежедневная ИИ-сводка",
        "AI weekly digest": "Еженедельная ИИ-сводка",
        "Deadline": "Срок",
        "deadline": "срок",
    }
    for old, new in replacements.items():
        text = text.replace(old, new)
    return text


