@app.post(
    "/platform/calendar-health/{company_id}/recover",
)
async def platform_calendar_incident_recover(
    request: Request,
    company_id: int,
):
    username = get_user(request)

    if not username:
        return RedirectResponse("/login", status_code=302)

    if get_role(username) != "superadmin":
        return RedirectResponse("/", status_code=302)

    form = await request.form()
    recovery_note = str(
        form.get("recovery_note") or ""
    ).strip()
    conn = connect()
    c = conn.cursor()
    company = c.execute("""
    SELECT
        companies.id,
        scheduler.active_incident,
        scheduler.incident_acknowledged_at,
        scheduler.incident_acknowledged_by,
        scheduler.incident_assigned_to
    FROM companies
    LEFT JOIN calendar_plan_scheduler_status AS scheduler
      ON scheduler.company_id=companies.id
    WHERE companies.id=?
    """, (company_id,)).fetchone()
    conn.close()

    if not company or not str(company["active_incident"] or ""):
        return RedirectResponse(
            (
                f"/platform/calendar-health/{company_id}"
                "?error=incident_not_found"
            ),
            status_code=302,
        )

    if not company["incident_acknowledged_at"]:
        return RedirectResponse(
            (
                f"/platform/calendar-health/{company_id}"
                "?error=incident_not_acknowledged"
            ),
            status_code=302,
        )

    assigned_to = str(
        company["incident_assigned_to"]
        or company["incident_acknowledged_by"]
        or ""
    )

    if assigned_to != username:
        return RedirectResponse(
            (
                f"/platform/calendar-health/{company_id}"
                "?error=incident_not_assignee"
            ),
            status_code=302,
        )

    if not recovery_note:
        return RedirectResponse(
            (
                f"/platform/calendar-health/{company_id}"
                "?error=recovery_note_required"
            ),
            status_code=302,
        )

    if len(recovery_note) > 500:
        return RedirectResponse(
            (
                f"/platform/calendar-health/{company_id}"
                "?error=recovery_note_too_long"
            ),
            status_code=302,
        )

    log_calendar_scheduler_recovery_attempt(
        company_id,
        "recovery_started",
        username,
        (
            "Платформа запустила внеплановую проверку автоматизации. "
            f"Комментарий ответственного: {recovery_note}"
        ),
    )
    result = await run_calendar_plan_scheduler(
        company_id,
        source="manual_run",
    )

    if result["error"]:
        error_code = (
            result["error"]
            if result["error"] in {
                "automation_disabled",
                "calendar_disabled",
                "scheduler_already_running",
                "actor_not_found",
            }
            else "recovery_failed"
        )
        log_calendar_scheduler_recovery_attempt(
            company_id,
            "recovery_failed",
            username,
            (
                "Внеплановая проверка завершилась с ошибкой: "
                f"{result['error']}. "
                f"Комментарий ответственного: {recovery_note}"
            ),
        )
        return RedirectResponse(
            (
                f"/platform/calendar-health/{company_id}"
                f"?error={error_code}"
            ),
            status_code=302,
        )

    close_calendar_scheduler_incident(
        company_id,
        actor_username=username,
        recovery_message=(
            "Платформа выполнила внеплановую проверку. "
            "Автоматизация календаря работает штатно. "
            f"Итог диагностики: {recovery_note}"
        ),
    )
    return RedirectResponse(
        (
            f"/platform/calendar-health/{company_id}"
            "?notice=recovered"
        ),
        status_code=302,
    )


@app.get("/my-tasks", response_class=HTMLResponse)
async def my_tasks_page(request: Request, status: str = ""):

    username = get_user(request)

    if not username:
        return RedirectResponse("/login", status_code=302)

    role = get_role(username)

    if role != "worker":
        return RedirectResponse("/", status_code=302)

    company_id = get_user_company_id(username)
    settings = get_company_settings(company_id)

    conn = connect()
    c = conn.cursor()

    query = """
    SELECT *
    FROM tasks
    WHERE archived=0
      AND company_id=?
    """

    query += f" AND {worker_task_condition()}"
    params = [company_id] + worker_task_params(username)

    if status:
        query += " AND status=?"
        params.append(status)
    else:
        query += " AND status!='Завершено'"

    query += " ORDER BY task_date DESC"

    tasks = c.execute(query, params).fetchall()

    conn.close()

    return templates.TemplateResponse(
        request,
        "my_tasks.html",
        {
            "request": request,
            "username": username,
            "role": role,
            "tasks": tasks,
            "selected_status": status,
            "settings": settings
        }
    )


@app.get("/", response_class=HTMLResponse)
async def home(
    request: Request,
    status: str = "",
    worker: str = "",
    task_date: str = "",
    search: str = ""
):

    username = get_user(request)

    if not username:
        return RedirectResponse("/login", status_code=302)

    update_last_seen(username)

    role = get_role(username)

    if role == "superadmin":
        return RedirectResponse("/platform", status_code=302)

    if role == "worker":
        return RedirectResponse("/my-tasks", status_code=302)

    company_id = get_user_company_id(username)
    features = get_company_features(company_id)

    conn = connect()
    c = conn.cursor()

    query = "SELECT * FROM tasks WHERE archived=0 AND company_id=?"
    params = [company_id]

    if role not in ("boss", "manager"):
        query += f" AND {worker_task_condition()}"
        params += worker_task_params(username)

    if status:
        query += " AND status=?"
        params.append(status)

    if worker and role in ("boss", "manager"):
        query += f" AND {worker_task_condition()}"
        params += worker_task_params(worker)

    if task_date:
        query += " AND task_date=?"
        params.append(task_date)

    if search:
        query += " AND client LIKE ?"
        params.append(f"%{search}%")

    query += " ORDER BY id DESC"

    tasks = c.execute(query, params).fetchall()

    if role in ("boss", "manager"):
        total_tasks = c.execute("SELECT COUNT(*) FROM tasks WHERE archived=0 AND company_id=?", (company_id,)).fetchone()[0]
        new_tasks = c.execute("SELECT COUNT(*) FROM tasks WHERE archived=0 AND company_id=? AND status='Новая'", (company_id,)).fetchone()[0]
        working_tasks = c.execute("SELECT COUNT(*) FROM tasks WHERE archived=0 AND company_id=? AND status='В работе'", (company_id,)).fetchone()[0]
        done_tasks = c.execute("SELECT COUNT(*) FROM tasks WHERE archived=0 AND company_id=? AND status='Завершено'", (company_id,)).fetchone()[0]

        revenue = c.execute("""
        SELECT SUM(price) FROM tasks WHERE archived=0 AND company_id=? AND status='Завершено'
        """, (company_id,)).fetchone()[0]
    else:
        worker_condition = worker_task_condition()
        worker_params = worker_task_params(username)

        total_tasks = c.execute(f"""
        SELECT COUNT(*) FROM tasks
        WHERE archived=0 AND company_id=? AND {worker_condition}
        """, [company_id] + worker_params).fetchone()[0]

        new_tasks = c.execute(f"""
        SELECT COUNT(*) FROM tasks
        WHERE archived=0 AND company_id=? AND {worker_condition}
          AND status='Новая'
        """, [company_id] + worker_params).fetchone()[0]

        working_tasks = c.execute(f"""
        SELECT COUNT(*) FROM tasks
        WHERE archived=0 AND company_id=? AND {worker_condition}
          AND status='В работе'
        """, [company_id] + worker_params).fetchone()[0]

        done_tasks = c.execute(f"""
        SELECT COUNT(*) FROM tasks
        WHERE archived=0 AND company_id=? AND {worker_condition}
          AND status='Завершено'
        """, [company_id] + worker_params).fetchone()[0]

        revenue = c.execute(f"""
        SELECT SUM(price) FROM tasks
        WHERE archived=0 AND company_id=? AND {worker_condition}
          AND status='Завершено'
        """, [company_id] + worker_params).fetchone()[0]

    if revenue is None:
        revenue = 0

    today = datetime.now().strftime("%Y-%m-%d")
    now_value = datetime.now().strftime("%Y-%m-%dT%H:%M")
    sla_soon_value = (datetime.now() + timedelta(hours=24)).strftime("%Y-%m-%dT%H:%M")

    today_tasks = c.execute("""
    SELECT COUNT(*)
    FROM tasks
    WHERE archived=0
      AND company_id=?
      AND task_date LIKE ?
    """, (company_id, f"{today}%")).fetchone()[0]

    overdue_tasks = c.execute("""
    SELECT COUNT(*)
    FROM tasks
    WHERE archived=0
      AND company_id=?
      AND status NOT IN ('Завершено', 'Отменено')
      AND task_date IS NOT NULL
      AND task_date!=''
      AND task_date < ?
    """, (company_id, today)).fetchone()[0]

    sla_breached_tasks = c.execute("""
    SELECT COUNT(*)
    FROM tasks
    WHERE archived=0
      AND company_id=?
      AND status NOT IN ('Завершено', 'Отменено')
      AND deadline_at IS NOT NULL
      AND deadline_at!=''
      AND deadline_at < ?
    """, (company_id, now_value)).fetchone()[0]

    sla_due_soon_tasks = c.execute("""
    SELECT COUNT(*)
    FROM tasks
    WHERE archived=0
      AND company_id=?
      AND status NOT IN ('Завершено', 'Отменено')
      AND deadline_at IS NOT NULL
      AND deadline_at!=''
      AND deadline_at >= ?
      AND deadline_at <= ?
    """, (company_id, now_value, sla_soon_value)).fetchone()[0]

    active_workers = c.execute("""
    SELECT COUNT(DISTINCT worker)
    FROM tasks
    WHERE archived=0
      AND company_id=?
      AND status='В работе'
    """, (company_id,)).fetchone()[0]


    workers = c.execute("""
    SELECT username, last_seen FROM users
    WHERE role='worker'
      AND company_id=?
      AND COALESCE(is_active, 1)=1
    ORDER BY username
    """, (company_id,)).fetchall()

    clients = []

    worker_stats = []

    if role in ("boss", "manager"):
        for w in workers:
            worker_name = w["username"]
            worker_condition = worker_task_condition()
            worker_params = worker_task_params(worker_name)

            completed = c.execute(f"""
            SELECT COUNT(*) FROM tasks
            WHERE archived=0 AND company_id=? AND {worker_condition}
              AND status='Завершено'
            """, [company_id] + worker_params).fetchone()[0]

            active = c.execute(f"""
            SELECT COUNT(*) FROM tasks
            WHERE archived=0 AND company_id=? AND {worker_condition}
              AND status='В работе'
            """, [company_id] + worker_params).fetchone()[0]

            worker_revenue = c.execute(f"""
            SELECT SUM(price) FROM tasks
            WHERE archived=0 AND company_id=? AND {worker_condition}
              AND status='Завершено'
            """, [company_id] + worker_params).fetchone()[0]

            if worker_revenue is None:
                worker_revenue = 0

            worker_stats.append({
                "username": worker_name,
                "completed": completed,
                "active": active,
                "revenue": worker_revenue,
                "last_seen": w["last_seen"]
            })

    settings = get_company_settings(company_id)

    conn.close()

    return templates.TemplateResponse(
        request=request,
        name="index.html",
        context={
            "tasks": tasks,
            "username": username,
            "role": role,
            "total_tasks": total_tasks,
            "new_tasks": new_tasks,
            "working_tasks": working_tasks,
            "done_tasks": done_tasks,
            "revenue": revenue,
            "today_tasks": today_tasks,
            "overdue_tasks": overdue_tasks,
            "sla_breached_tasks": sla_breached_tasks,
            "sla_due_soon_tasks": sla_due_soon_tasks,
            "active_workers": active_workers,
            "workers": workers,
            "worker_stats": worker_stats,
            "selected_status": status,
            "selected_worker": worker,
            "selected_date": task_date,
            "search": search,
            "features": features,
            "settings": settings
        }
    )


