@app.get("/workload", response_class=HTMLResponse)
async def workload_page(request: Request):

    username = get_user(request)

    if not username:
        return RedirectResponse("/login", status_code=302)

    role = get_role(username)

    if role not in ("boss", "manager"):
        return RedirectResponse("/", status_code=302)

    company_id = get_user_company_id(username)
    disabled_response = require_feature(company_id, "workload")

    if disabled_response:
        return disabled_response

    settings = get_company_settings(company_id)

    conn = connect()
    c = conn.cursor()

    workers = c.execute("""
    SELECT username, full_name, position, last_seen
    FROM users
    WHERE role='worker'
      AND company_id=?
      AND COALESCE(is_active, 1)=1
    ORDER BY username
    """, (company_id,)).fetchall()

    stats = []

    for worker in workers:
        name = worker["username"]

        total = c.execute(f"""
        SELECT COUNT(*)
        FROM tasks
        WHERE archived=0
          AND company_id=?
          AND ({worker_task_condition()})
        """, [company_id] + worker_task_params(name)).fetchone()[0]

        active = c.execute(f"""
        SELECT COUNT(*)
        FROM tasks
        WHERE archived=0
          AND company_id=?
          AND status='В работе'
          AND ({worker_task_condition()})
        """, [company_id] + worker_task_params(name)).fetchone()[0]

        new = c.execute(f"""
        SELECT COUNT(*)
        FROM tasks
        WHERE archived=0
          AND company_id=?
          AND status='Новая'
          AND ({worker_task_condition()})
        """, [company_id] + worker_task_params(name)).fetchone()[0]

        done = c.execute(f"""
        SELECT COUNT(*)
        FROM tasks
        WHERE archived=0
          AND company_id=?
          AND status='Завершено'
          AND ({worker_task_condition()})
        """, [company_id] + worker_task_params(name)).fetchone()[0]

        if active >= 3:
            load_status = "Перегружен"
        elif active == 0 and new == 0:
            load_status = "Свободен"
        else:
            load_status = "В норме"

        stats.append({
            "worker": worker,
            "total": total,
            "active": active,
            "new": new,
            "done": done,
            "load_status": load_status
        })

    conn.close()

    return templates.TemplateResponse(
        request,
        "workload.html",
        {
            "request": request,
            "username": username,
            "role": role,
            "stats": stats,
            "settings": settings
        }
    )


@app.post("/sla/reminders")
async def create_sla_reminders(request: Request):

    username = get_user(request)

    if not username:
        return RedirectResponse("/login", status_code=302)

    role = get_role(username)

    if role not in ("boss", "manager"):
        return RedirectResponse("/", status_code=302)

    company_id = get_user_company_id(username)
    disabled_response = require_feature(company_id, "sla")

    if disabled_response:
        return disabled_response

    now_value = datetime.now().strftime("%Y-%m-%dT%H:%M")
    soon_value = (datetime.now() + timedelta(hours=24)).strftime("%Y-%m-%dT%H:%M")

    conn = connect()
    c = conn.cursor()

    tasks = c.execute("""
    SELECT *
    FROM tasks
    WHERE archived=0
      AND company_id=?
      AND status!='Завершено'
      AND deadline_at IS NOT NULL
      AND deadline_at!=''
      AND deadline_at < ?
    ORDER BY deadline_at ASC
    """, (company_id, now_value)).fetchall()

    users = c.execute("""
    SELECT username
    FROM users
    WHERE company_id=?
      AND role IN ('boss', 'manager')
    """, (company_id,)).fetchall()

    created_count = 0
    automation_tasks = []

    for task in tasks:
        task_created_count = 0

        for user in users:
            existing_notification = c.execute("""
            SELECT id
            FROM notifications
            WHERE company_id=?
              AND username=?
              AND title=?
              AND link=?
              AND is_read=0
            """, (
                company_id,
                user["username"],
                "🔴 Просрочен SLA",
                f"/task/{task['id']}"
            )).fetchone()

            if existing_notification:
                continue

            c.execute("""
            INSERT INTO notifications (
                company_id,
                username,
                title,
                message,
                link,
                created_at
            )
            VALUES (?, ?, ?, ?, ?, ?)
            """, (
                company_id,
                user["username"],
                "🔴 Просрочен SLA",
                f"Заявка #{task['id']} просрочила срок SLA",
                f"/task/{task['id']}",
                datetime.now().strftime("%Y-%m-%d %H:%M")
            ))
            created_count += 1
            task_created_count += 1

        if task_created_count:
            automation_tasks.append(task)

    conn.commit()
    conn.close()

    for task in automation_tasks:
        run_automation_event(
            company_id,
            "sla_overdue",
            "task",
            task["id"],
            f"Заявка #{task['id']} просрочила срок SLA",
            f"/task/{task['id']}"
        )

    return RedirectResponse(f"/sla?reminders=1&created={created_count}&filter=overdue", status_code=302)


