    for event in diagnostics["system_events"]:
        writer.writerow([
            event["created_at"],
            event["severity_label"],
            event["source"],
            event["username"],
            event["message"],
            event["details"],
        ])

    return Response(
        "\ufeff" + output.getvalue(),
        media_type="text/csv; charset=utf-8",
        headers={
            "Content-Disposition": "attachment; filename=system_report.csv",
        },
    )


