@app.post("/task/{task_id}/complete")
async def complete_task(request: Request, task_id: int):

    username = get_user(request)

    if not username:
        return RedirectResponse("/login", status_code=302)

    role = get_role(username)

    if role != "worker":
        return RedirectResponse("/", status_code=302)

    form = await request.form()
    report = (form.get("report") or "").strip()
    after_photo = form.get("after_photo")

    if not report:
        return RedirectResponse("/my-tasks?error=report_required", status_code=302)

    company_id = get_user_company_id(username)

    conn = connect()
    c = conn.cursor()

    task = c.execute("""
    SELECT *
    FROM tasks
    WHERE id=? AND company_id=?
    """, (task_id, company_id)).fetchone()

    if not task or not task_has_worker(username, task):
        conn.close()
        return RedirectResponse("/my-tasks", status_code=302)

    filename = save_upload_file(after_photo, task_id, "after")

    c.execute("""
    UPDATE tasks
    SET status='Завершено',
        report=?,
        after_photo=?
    WHERE id=?
    """, (
        report,
        filename or task["after_photo"],
        task_id
    ))

    c.execute("""
    INSERT INTO task_activity (
        task_id,
        username,
        role,
        action,
        details,
        created_at
    )
    VALUES (?, ?, ?, ?, ?, ?)
    """, (
        task_id,
        username,
        role,
        "Завершил заявку",
        report,
        datetime.now().strftime("%Y-%m-%d %H:%M")
    ))

    owners = c.execute("""
    SELECT username
    FROM users
    WHERE company_id=? AND role IN ('boss', 'manager')
    """, (company_id,)).fetchall()

    for owner in owners:
        c.execute("""
        INSERT INTO notifications (
            company_id,
            username,
            title,
            message,
            link,
            created_at
        )
        VALUES (?, ?, ?, ?, ?, ?)
        """, (
            company_id,
            owner["username"],
            "✅ Заявка завершена",
            f"Исполнитель {username} завершил заявку #{task_id}",
            f"/task/{task_id}",
            datetime.now().strftime("%Y-%m-%d %H:%M")
        ))

    conn.commit()
    conn.close()

    if task["status"] != "Завершено":
        run_automation_event(
            company_id,
            "task_status_changed",
            "task",
            task_id,
            f"Статус заявки #{task_id}: {task['status']} → Завершено",
            f"/task/{task_id}",
        )

    try:
        send_message(
            f"""
✅ Заявка завершена исполнителем

Заявка: #{task_id}
Клиент: {task["client"]}
Адрес: {task["address"]}
Исполнитель: {username}

Отчёт:
{report}
"""
        )
    except Exception:
        pass

    return RedirectResponse("/my-tasks", status_code=302)


